#MANUAL SPARQL
PREFIX ns: <http://rdf.freebase.com/ns/>
SELECT DISTINCT ?x
WHERE {
	FILTER (?x != ns:m.024v2j)
	{ 
	  # Parents
	  ns:m.024v2j ns:people.person.parents ?x .
	}
	UNION
	{
	  # Children
	  ns:m.024v2j ns:people.person.children ?x .
	}
	UNION
	{
	  # Siblings
	  ns:m.024v2j ns:people.person.sibling_s ?y .
	  ?y ns:people.sibling_relationship.sibling ?x .
	}
	UNION
	{
	  # Spouse
	  ns:m.024v2j ns:people.person.spouse_s ?y .
	  ?y ns:people.marriage.spouse ?x .
	  ?y ns:people.marriage.type_of_union ns:m.04ztj .
	  FILTER (NOT EXISTS {?y ns:people.marriage.to []})
	}
}

#MANUAL SPARQL
PREFIX ns: <http://rdf.freebase.com/ns/>
SELECT DISTINCT ?x
WHERE {
  {
    SELECT ?pFrom 
    WHERE {
      ns:m.02yy8 ns:government.politician.government_positions_held ?y . # Franklin D. Roosevelt
      ?y ns:government.government_position_held.office_position_or_title ?x ; 
         ns:government.government_position_held.basic_title ns:m.060c4 ; # President
         ns:government.government_position_held.from ?pFrom .
    }
  }
  ns:m.02yy8 ns:government.politician.government_positions_held ?y . # Franklin D. Roosevelt
  ?y ns:government.government_position_held.office_position_or_title ?x ; 
     ns:government.government_position_held.from ?from .

  FILTER(xsd:dateTime(?pFrom) - xsd:dateTime(?from) > 0)
}
